```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"

using namespace sqlgen;
using namespace sqlgen::literals;

namespace detail {

// Map table name to its reflected C++ type for runtime dispatch
inline std::string normalize_name(const std::string& name) {
  std::string res = name;
  for (auto& c : res) c = static_cast<char>(::tolower(c));
  return res;
}

template <typename Fn>
void dispatch_by_table(const std::string& table_name, Fn&& fn) {
  const auto t = normalize_name(table_name);

  if (t == "student" || t == "students") {
    fn.template operator()<Student>();
  } else if (t == "course" || t == "courses") {
    fn.template operator()<Course>();
  } else if (t == "score" || t == "scores") {
    fn.template operator()<Score>();
  } else if (t == "major" || t == "majors") {
    fn.template operator()<Major>();
  } else {
    throw std::runtime_error("Unknown table name: " + table_name);
  }
}

}  // namespace detail

// Generic add function (templated on record type)
template <typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to SQLite database
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database: " +
                             conn_res.error());
  }
  auto& conn = conn_res.value();

  // Insert all records in a single transaction
  auto tx_res = sqlgen::transaction(conn, [&](auto& tx_conn) -> expected<void> {
    for (const auto& rec : records) {
      auto r = sqlgen::insert(rec).exec(tx_conn);
      if (!r) {
        return unexpected(r.error());
      }
    }
    return {};
  });

  if (!tx_res) {
    throw std::runtime_error("Failed to insert records into table " +
                             table_name + ": " + tx_res.error());
  }
}

// Modify a single column of a record identified by primary key
// record_id is passed as string and converted by sqlgen
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const std::string& new_value) {
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database: " +
                             conn_res.error());
  }
  auto& conn = conn_res.value();

  detail::dispatch_by_table(table_name, [&](auto type_tag) {
    using T = decltype(type_tag)::type;  // but we can't actually get type_tag;
                                         // instead use template< typename X >
  });

  // The above lambda can't deduce like that directly, so use a struct with
  // template operator():
  struct Modifier {
    std::string table_name;
    std::string record_id;
    std::string col_name;
    std::string new_value;
    sqlgen::sqlite::connection& conn;

    template <typename T>
    void operator()() {
      // Build an UPDATE statement using sqlgen's fluent API
      // WHERE primary_key = record_id
      auto update_stmt =
          sqlgen::update<T>()
              .set(col_name, new_value)                // value converted by sqlgen
              .where(sqlgen::primary_key<T>() == record_id);

      auto r = update_stmt.exec(conn);
      if (!r) {
        throw std::runtime_error("Failed to modify record in table " +
                                 table_name + ": " + r.error());
      }
    }
  };

  detail::dispatch_by_table(
      table_name,
      Modifier{table_name, record_id, col_name, new_value, conn});
}

// Delete a record by primary key
inline void delete_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id) {
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database: " +
                             conn_res.error());
  }
  auto& conn = conn_res.value();

  struct Deleter {
    std::string table_name;
    std::string record_id;
    sqlgen::sqlite::connection& conn;

    template <typename T>
    void operator()() {
      auto del_stmt =
          sqlgen::delete_from<T>().where(sqlgen::primary_key<T>() == record_id);

      auto r = del_stmt.exec(conn);
      if (!r) {
        throw std::runtime_error("Failed to delete record from table " +
                                 table_name + ": " + r.error());
      }
    }
  };

  detail::dispatch_by_table(table_name,
                            Deleter{table_name, record_id, conn});
}
