  //    WHERE p.created_at >= DATE('2025-12-01')
  //      AND p.created_at <= DATE('2025-12-31');
  //
  //    We attach this SQL to the ActiveUser "view" entity.
  drop_view_if_exists<ActiveUser>(conn);

  {
    std::string view_sql =
        "CREATE VIEW ActiveUserView AS "
        "SELECT DISTINCT u.user_id AS user_id, u.username AS username "
        "FROM User u "
