struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;

  // Needed by sqlgen to map to a query result
  SQLGEN_DECLARE_VIEW(CourseStatsView, title, student_count, avg_grade)
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  // Connect to SQLite database "test_db.sqlite"
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Create tables if they don't already exist
  db.create_table<Course>();
  db.create_table<Enrollment>();

  // Build the query that corresponds to:
  // SELECT c.title,
  //        COUNT(e.enrollment_id) AS student_count,
  //        AVG(e.grade)           AS avg_grade
  // FROM Course c
  // LEFT JOIN Enrollment e ON c.course_id = e.course_id
  // GROUP BY c.course_id, c.title;
  auto query =
      sqlgen::select<CourseStatsView>(db)
          .columns(
              sqlgen::column<Course>(&Course::title),
              sqlgen::count(sqlgen::column<Enrollment>(&Enrollment::enrollment_id))
                  .as(&CourseStatsView::student_count),
              sqlgen::avg(sqlgen::column<Enrollment>(&Enrollment::grade))
                  .as(&CourseStatsView::avg_grade))
          .from<Course>()
          .left_join<Enrollment>(
              sqlgen::on(sqlgen::column<Course>(&Course::course_id) ==
                         sqlgen::column<Enrollment>(&Enrollment::course_id)))
          .group_by(sqlgen::column<Course>(&Course::course_id),
                    sqlgen::column<Course>(&Course::title));

  std::vector<CourseStatsView> rows = query.exec();

  std::vector<CourseStats> result;
  result.reserve(rows.size());

  for (const auto& r : rows) {
    result.push_back(CourseStats{
        r.title,
        r.student_count,
        r.avg_grade,
    });
  }

  return result;
}

}  // namespace query_course_enrollment_stats
