 * 
 * @param customer_id ID of the customer to query
 * @return List of purchase history items
 */
std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  using namespace sqlgen;

  // 1. Connect to the SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // 2. Create Customer, Order, OrderItem, Product tables
  //    sqlgen::migrate will create (or update) the schema for these structs.
  migrate<Customer>(db);
  migrate<Product>(db);
  migrate<Order>(db);
  migrate<OrderItem>(db);

  // 3. Query all products purchased by a specific customer
  //    We follow the reference SQL, but use sqlgen's query API.
  //
  //    SELECT p.name, o.order_date, oi.quantity
  //    FROM Customer c
  //    JOIN "Order" o ON c.customer_id = o.customer_id
  //    JOIN OrderItem oi ON o.order_id = oi.order_id
  //    JOIN Product p ON oi.product_id = p.product_id
  //    WHERE c.customer_id = ?
  //    ORDER BY o.order_date DESC;

  std::vector<PurchaseHistory> results;

  // We build and execute the query using raw SQL via the underlying sqlite
  // connection exposed by sqlgen.
  {
    sqlite::Statement stmt(
        db,
        "SELECT p.name, o.order_date, oi.quantity "
        "FROM Customer c "
        "JOIN \"Order\" o ON c.customer_id = o.customer_id "
        "JOIN OrderItem oi ON o.order_id = oi.order_id "
        "JOIN Product p ON oi.product_id = p.product_id "
        "WHERE c.customer_id = ? "
        "ORDER BY o.order_date DESC;");

    stmt.bind(1, customer_id);

    while (stmt.step()) {
      PurchaseHistory ph{};

      ph.product_name = stmt.column_text(0);

      // column 1: order_date as text, parse into sqlgen::Timestamp
      {
        std::string ts_str = stmt.column_text(1);
        ph.order_date = sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">(ts_str);
      }

      ph.quantity = stmt.column_int(2);

      results.push_back(std::move(ph));
    }
  }

  // 4. Return the results as a vector of PurchaseHistory
  return results;
}

}  // namespace query_customer_purchase_history
