std::vector<CategoryReport> query_product_sales_report() {
  // Open SQLite connection to test_db.sqlite
  sqlgen::sqlite::connection conn{"test_db.sqlite"};

  // Define table handles
  auto product = sqlgen::sqlite::table<Product>(conn, "Product");
  auto sale    = sqlgen::sqlite::table<Sale>(conn, "Sale");

  namespace sg = sqlgen;

  // Build the query:
  // SELECT p.category, SUM(s.quantity) AS total_qty, SUM(s.amount) AS total_amt
  // FROM Product p
  // INNER JOIN Sale s ON p.product_id = s.product_id
  // GROUP BY p.category
  // HAVING total_amt > 5000;
  auto q = sg::select(
              product.col(&Product::category),
              sg::sum(sale.col(&Sale::quantity)).as("total_qty"),
              sg::sum(sale.col(&Sale::amount)).as("total_amt"))
           .from(product)
           .join(sale, product.col(&Product::product_id) == sale.col(&Sale::product_id))
           .group_by(product.col(&Product::category))
           .having(sg::sum(sale.col(&Sale::amount)) > 5000.0);

  std::vector<CategoryReport> result;
  result.reserve(16);  // arbitrary small reserve

  conn.exec(
