  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
  // Open SQLite database connection
  sqlgen::sqlite::connection conn("test_db.sqlite");

  // Start with base query
  std::string query = "SELECT book_id, title, author, year, genre, price FROM Book";
  std::vector<std::string> conditions;
  std::vector<sqlgen::param> params;

  // Dynamically build WHERE clauses and bind parameters

  // Title keyword: use LIKE with wildcards
  if (filters.title_keyword.has_value()) {
    conditions.emplace_back("title LIKE ?");
    params.emplace_back("%" + *filters.title_keyword + "%");
  }

  // Minimum year: year >= ?
  if (filters.min_year.has_value()) {
    conditions.emplace_back("year >= ?");
    params.emplace_back(*filters.min_year);
  }

  // Genre equality: genre = ?
  if (filters.genre.has_value()) {
    conditions.emplace_back("genre = ?");
    params.emplace_back(*filters.genre);
  }

  // Maximum price: price <= ?
  if (filters.max_price.has_value()) {
    conditions.emplace_back("price <= ?");
    params.emplace_back(*filters.max_price);
  }

  // Append WHERE clause if we have any conditions
  if (!conditions.empty()) {
    query += " WHERE ";
    for (std::size_t i = 0; i < conditions.size(); ++i) {
      if (i > 0) {
        query += " AND ";
      }
      query += conditions[i];
    }
  }

  // Execute query and map results to Book objects via sqlgen
  auto stmt = conn.prepare(query);
  stmt.bind(params);
  return stmt.execute<Book>();
}

