      .phone_number = "1234567890",
      .is_active = true};

  // Note: sqlgen doesn't automatically map UserAfter to "User" table unless we specify it or rename struct.
  // But insert<UserAfter> will try to insert into "UserAfter" table by default.
  // So we need to use `insert` into "User" table with fields.
  // Or we can just use raw SQL to verify or use a struct with same name in a different namespace/scope if we want to map to "User".
