bool migration_add_column() {
  try {
    // Open connection to SQLite database "test_db.sqlite"
    sqlgen::sqlite::Connection conn{"test_db.sqlite"};

    // We will run ALTER TABLE statements and ignore "duplicate column" errors,
    // but fail on any other errors.

    auto alter_column = [&](const std::string& sql) {
      try {
        sqlgen::sqlite::Statement stmt{conn, sql};
        stmt.exec();
        return true;
      } catch (const std::exception& e) {
        std::string msg = e.what();
        // SQLite typically reports existing column issues with:
        // "duplicate column name: <column>"
