#pragma once

#include <stdexcept>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  // Reject non‑positive transfers
  if (amount <= 0.0) {
    return false;
  }

  try {
    // Connect to SQLite database
    sqlgen::sqlite::Connection conn("test_db.sqlite");

    // Wrap DB handle in sqlgen database object
    sqlgen::Database db(conn);

    // Start transaction
    db.begin();

    // 1) Load sender account
    auto from_acc_opt = db.get<Account>(from_account_id);
    if (!from_acc_opt) {
      db.rollback();
      return false;
    }
    Account from_acc = *from_acc_opt;

    // 2) Verify sufficient funds
    if (from_acc.balance < amount) {
      db.rollback();
      return false;
    }

    // 3) Load receiver account
    auto to_acc_opt = db.get<Account>(to_account_id);
    if (!to_acc_opt) {
      db.rollback();
      return false;
    }
    Account to_acc = *to_acc_opt;

    // 4) Perform in‑memory updates
    from_acc.balance -= amount;
    to_acc.balance   += amount;

    // 5) Persist updates
    // sqlgen will generate appropriate UPDATE statements under the same transaction
    db.update(from_acc);
    db.update(to_acc);

    // 6) Commit transaction
    db.commit();
    return true;
  } catch (const std::exception&) {
    // On any exception, attempt rollback and signal failure
    try {
      sqlgen::sqlite::Connection conn("test_db.sqlite");
      sqlgen::Database db(conn);
      db.rollback();
    } catch (...) {
      // Ignore rollback errors
    }
    return false;
  }
}

}  // namespace transaction_transfer_funds
