/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  // Open SQLite connection to "test_db.sqlite"
  sqlgen::sqlite::Connection connection{"test_db.sqlite"};

  // NOTE:
  // SQLite does not support RIGHT JOIN directly. To demonstrate
  // "right join" behavior (include all departments, even those
  // without projects), we emulate a RIGHT JOIN by using a LEFT
  // JOIN with the tables swapped:
  //
  //   Projects RIGHT JOIN Departments
  //   == Departments LEFT JOIN Projects
  //
  // So we treat Department as the left table and Project as the
  // right table in the join.

  std::vector<DepProj> result;

  // Build and execute the query using sqlgen's read API.
  // We explicitly select the department name and project name.
  auto rows = sqlgen::read<
      sqlgen::Select<
          sqlgen::Column<&Department::name>,
          sqlgen::Column<&Project::name>>,
      sqlgen::From<Department>,
      sqlgen::LeftJoin<Project,
                       sqlgen::On<sqlgen::Field<&Department::department_id>,
                                  sqlgen::Equal,
                                  sqlgen::Field<&Project::department_id>>>>
      (connection);

  result.reserve(rows.size());

  for (const auto& row : rows) {
    DepProj dp;
    // row is a std::tuple<optional<std::string>, optional<std::string>> (or similar)
    // depending on sqlgen's representation for nullable join fields.
    // The department_name should always exist (LEFT side), but we keep it optional
    // per the DepProj definition. The project_name may be null when a department
    // has no projects; we map that to an empty string.
    const auto& deptNameOpt = std::get<0>(row);
    const auto& projNameOpt = std::get<1>(row);

    if (deptNameOpt.has_value()) {
      dp.department_name = deptNameOpt.value();
    } else {
      dp.department_name = std::nullopt;
    }

    if (projNameOpt.has_value()) {
      dp.project_name = projNameOpt.value();
    } else {
      // For departments without projects, we expose an empty string as project_name.
      dp.project_name = "";
    }

    result.push_back(std::move(dp));
  }

  return result;
}

}  // namespace right_join_departments_projects
