  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Connects to the SQLite database "test_db.sqlite", ensures the Event table
 * exists, inserts the provided events (ignoring conflicts on primary key),
 * and runs a query to extract date/time parts and compute duration. Returns
 * the results as a vector of TemporalAnalysis for each event that has an
 * end_time.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data (const std::vector<Event>& events)  {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // Create the Event table if it does not exist.
  // Use a SQLite-compatible schema; sqlgen will map struct fields appropriately.
  {
    auto stmt = db.prepare(R"SQL(
      CREATE TABLE IF NOT EXISTS Event (
        event_id    INTEGER PRIMARY KEY,
        event_name  TEXT NOT NULL,
        start_time  TEXT NOT NULL,
        end_time    TEXT,
        created_at  TEXT NOT NULL
      );
    )SQL");
    stmt.execute();
  }

  // Insert or replace events into the Event table using sqlgen.
  // We use a transaction for efficiency.
  {
    sqlite::Transaction tx(db);
    auto inserter = make_inserter<Event>(db, "Event");

    for (const auto& e : events) {
      // INSERT OR REPLACE so that repeated analyses do not fail on PK conflicts.
      inserter.insert_or_replace(e);
    }

    tx.commit();
  }

  // Prepare and execute the temporal analysis query.
  //
  // The reference SQL uses functions (DAY, MONTH, YEAR, HOUR, MINUTE, SECOND,
  // WEEKDAY, UNIXEPOCH, DAYS_BETWEEN) that are not standard SQLite functions.
  // We emulate them using SQLite's built-in strftime, julianday, and related
  // functions.
  //
  //  - Day, month, year, hour, minute, second are extracted via strftime and
  //    cast to integers.
  //  - Weekday is derived from strftime('%w', ...) (0=Sunday, 6=Saturday).
  //    If you want Monday=0, you can adjust with a CASE expression.
  //  - start_epoch: (julianday(...) - 2440587.5) * 86400
  //  - duration_days: julianday(end_time) - julianday(start_time)
  //
  // Only rows with non-NULL end_time are included.
  const char* analysis_sql = R"SQL(
    SELECT
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) AS start_day,
      CAST(strftime('%m', start_time) AS INTEGER) AS start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) AS start_year,
      CAST(strftime('%H', start_time) AS INTEGER) AS start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) AS start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) AS start_second,
      -- strftime('%w'): 0=Sunday .. 6=Saturday
      CAST(strftime('%w', start_time) AS INTEGER) AS start_weekday,
      CAST((julianday(start_time) - 2440587.5) * 86400 AS INTEGER) AS start_epoch,
      (julianday(end_time) - julianday(start_time)) AS duration_days
    FROM Event
    WHERE end_time IS NOT NULL
  )SQL";

  auto stmt = db.prepare(analysis_sql);

  std::vector<TemporalAnalysis> results;
  while (stmt.step()) {
    TemporalAnalysis row{};
    int col = 0;

    row.event_id      = stmt.column_int(col++);
    row.event_name    = stmt.column_text(col++);
    row.start_day     = stmt.column_int(col++);
    row.start_month   = stmt.column_int(col++);
    row.start_year    = stmt.column_int(col++);
    row.start_hour    = stmt.column_int(col++);
    row.start_minute  = stmt.column_int(col++);
    row.start_second  = stmt.column_int(col++);
    row.start_weekday = stmt.column_int(col++);
    row.start_epoch   = stmt.column_int64(col++);

    if (stmt.column_type(col) == sqlite::ColumnType::Null) {
      row.duration_days = std::nullopt;
    } else {
      row.duration_days = stmt.column_double(col);
    }

    results.push_back(std::move(row));
  }

  return results;
}

}  // namespace analyze_temporal_data

