  // Define mapping between struct Inventory and the Inventory table
  return sqlgen::schema<Inventory>(
      "Inventory",
      sqlgen::field(&Inventory::item_id, "item_id"),
      sqlgen::field(&Inventory::name, "name"),
      sqlgen::field(&Inventory::quantity, "quantity"));
}

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table and verifies
 * the upsert behavior by reading the items back.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  using namespace sqlgen;

  if (items.empty()) {
    return true;  // nothing to do, but not an error
  }

  try {
    // Connect to the SQLite database "test_db.sqlite"
    sqlite::database db("test_db.sqlite");

    auto schema = make_schema();

    // Upsert (insert or replace) the given items
    {
      auto writer = make_writer(db, schema);
      // sqlgen's write API usually allows bulk operations on ranges/containers
      writer.insert_or_replace(items);
    }

    // Verify: read back the items that were just upserted
    {
      auto reader = make_reader(db, schema);

      // Collect the primary keys we just upserted
      std::vector<int> ids;
      ids.reserve(items.size());
      for (const auto& it : items) {
        ids.push_back(it.item_id);
      }

      // Read back by primary key set
      auto loaded = reader.get_by_primary_keys(ids);

      // Basic verification: we should have the same number of rows
      if (loaded.size() != items.size()) {
        return false;
      }

      // Optionally verify each item matches (id, name, quantity)
      // This assumes no concurrent modification.
      for (const auto& src : items) {
        bool found_match = false;
        for (const auto& dst : loaded) {
          if (dst.item_id == src.item_id &&
              dst.name == src.name &&
              dst.quantity == src.quantity) {
            found_match = true;
            break;
          }
        }
        if (!found_match) {
          return false;
        }
      }
    }

    return true;
  } catch (...) {
    // Any failure in DB access or sqlgen operations => return false
    return false;
  }
}

}  // namespace upsert_inventory_items
