```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating SQL tables for User and Friendship in
 * the SQLite database "test_db.sqlite".
 *
 * This function:
 *  1. Creates tables User and Friendship (if not exist) with the requested schema.
 *  2. Inserts the provided users and friendships.
 *  3. Runs multiple analysis queries:
 *     - Mutual friends via self-join + EXISTS
 *     - Nested query to find users with more than N friends
 *     - Friend-of-friend relationships
 *     - Aggregation-based network statistics
 *     - City-based recommendation for non‑friends
 *
 * For demonstration, it returns all mutual-friend pairs as FriendConnection.
 */
std::vector<FriendConnection> analyze_social_network_impl(
    const std::vector<User>& users,
    const std::vector<Friendship>& friendships) {
  using namespace sqlgen;

  // Open / create database
  sqlite::Database db("test_db.sqlite");

  // Create User table with the requested schema
  db.exec(R"SQL(
    CREATE TABLE IF NOT EXISTS User (
      user_id     INTEGER PRIMARY KEY,
      username    VARCHAR(50)  NOT NULL UNIQUE,
      email       VARCHAR(100) NOT NULL UNIQUE,
      join_date   DATETIME     NOT NULL,
      city        VARCHAR(50)
    );
  )SQL");

  // Create Friendship table with the requested schema
  db.exec(R"SQL(
    CREATE TABLE IF NOT EXISTS Friendship (
      user_id1        INTEGER NOT NULL,
      user_id2        INTEGER NOT NULL,
      friendship_date DATETIME NOT NULL,
      PRIMARY KEY (user_id1, user_id2),
      FOREIGN KEY (user_id1) REFERENCES User(user_id),
      FOREIGN KEY (user_id2) REFERENCES User(user_id)
    );
  )SQL");

  // For repeatable analysis, clear existing data.
  db.exec("DELETE FROM Friendship;");
  db.exec("DELETE FROM User;");

  // Insert data from the in-memory vectors into the DB.
  {
    sqlite::Statement insert_user(
        db,
        "INSERT INTO User (user_id, username, email, join_date, city) "
        "VALUES (?, ?, ?, datetime('now'), NULL);");

    for (const auto& u : users) {
      insert_user.reset();
      insert_user.bind(1, u.user_id.value());
      insert_user.bind(2, u.username);
      // Synthetic email from username for this example
      std::string email = u.username + "@example.com";
      insert_user.bind(3, email);
      insert_user.step();
    }
  }

  {
    sqlite::Statement insert_friend(
        db,
        "INSERT OR IGNORE INTO Friendship "
        "(user_id1, user_id2, friendship_date) "
        "VALUES (?, ?, ?);");

    for (const auto& f : friendships) {
      insert_friend.reset();
      insert_friend.bind(1, f.user1_id);
      insert_friend.bind(2, f.user2_id);
      insert_friend.bind(3, f.created_at.to_string());
      insert_friend.step();

      // Assuming undirected friendship, insert symmetric row as well
      insert_friend.reset();
      insert_friend.bind(1, f.user2_id);
      insert_friend.bind(2, f.user1_id);
      insert_friend.bind(3, f.created_at.to_string());
      insert_friend.step();
    }
  }

  // 1. Mutual friends via self-join with EXISTS (example from prompt)
  std::vector<FriendConnection> mutual_friend_pairs;
  {
    const char* sql_mutual = R"SQL(
      SELECT u1.username,
             u2.username,
             COUNT(f1.user_id2) AS mutual_friends
      FROM User u1
      INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
      INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
      INNER JOIN User u2 ON f2.user_id2 = u2.user_id
      WHERE u1.user_id < u2.user_id
        AND EXISTS (
          SELECT 1
          FROM Friendship f3
          WHERE f3.user_id1 = u1.user_id
            AND f3.user_id2 = u2.user_id
        )
      GROUP BY u1.user_id, u2.user_id
      HAVING COUNT(f1.user_id2) > 0;
    )SQL";

    sqlite::Statement stmt(db, sql_mutual);
    while (stmt.step()) {
      FriendConnection fc;
      fc.user1_name = stmt.column_text(0);
      fc.user2_name = stmt.column_text(1);
      mutual_friend_pairs.push_back(fc);
    }
  }

  // 2. Nested query: users with more than N friends (N derived via subquery)
  {
    const char* sql_more_than_avg = R"SQL(
      SELECT u.user_id, u.username, COUNT(f.user_id2) AS friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user_id1
      GROUP BY u.user_id, u.username
      HAVING friend_count > (
        SELECT AVG(friend_count)
        FROM (
          SELECT COUNT(*) AS friend_count
          FROM Friendship
          GROUP BY user_id1
        )
      )
      ORDER BY friend_count DESC;
    )SQL";

    sqlite::Statement stmt(db, sql_more_than_avg);
    while (stmt.step()) {
