#pragma once

#include <cmath>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace mathematical_operations_analysis {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int quantity;
  double discount_rate;
};

struct MathAnalysis {
  int product_id;
  std::string name;
  double abs_price;
  double ceil_price;
  double floor_price;
  double rounded_price;
  double exp_discount;
  double ln_price;
  double log2_quantity;
  double sin_discount;
  double cos_discount;
  double tan_discount;
  double sqrt_quantity;
};

/**
 * Insert products into an SQLite Product table and run a SELECT that computes
 * various mathematical expressions, returning results as std::vector<MathAnalysis>.
 *
 * This function assumes that a SQLite database file named "test_db.sqlite"
 * is accessible and uses sqlgen's reflection to map the Product struct
 * to a "Product" table.
 */
std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  using namespace sqlgen;

  // Open/create the SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // Create reflection metadata for Product
  using ProductOrm = Orm<Product,
    Member<&Product::product_id, ColumnName<"product_id">>,
    Member<&Product::name,       ColumnName<"name">>,
    Member<&Product::price,      ColumnName<"price">>,
    Member<&Product::quantity,   ColumnName<"quantity">>,
    Member<&Product::discount_rate, ColumnName<"discount_rate">>,
    TableName<"Product">
  >;

  // Ensure the Product table exists
  ProductOrm::create_table(db);

  // Clear existing rows so the analysis is based only on provided products
  {
    auto stmt = db.prepare("DELETE FROM Product;");
    stmt.exec();
  }

  // Insert the provided products
  {
    auto inserter = ProductOrm::insert(db);
    for (const auto& p : products) {
      inserter(p);
    }
  }

  // We will compute the requested mathematical operations. SQLite does not
  // have all of these functions built-in in all builds (e.g., CEIL, FLOOR,
  // LOG2), so for portability we fetch the raw data and compute those values
  // in C++ instead, while still demonstrating one example of using SQL
  // mathematical functions (ABS and ROUND) directly in the query.
  //
  // If the underlying SQLite build has the math extension loaded, the
  // reference SQL in the user description could be issued directly.

  std::vector<MathAnalysis> results;

  // Fetch base data plus some simple SQL-computed fields (ABS, ROUND)
  auto stmt = db.prepare(
      "SELECT product_id, name, price, quantity, discount_rate, "
      "ABS(price) AS abs_price_sql, "
      "ROUND(price, 2) AS rounded_price_sql "
      "FROM Product;"
  );

  while (stmt.step()) {
    MathAnalysis m{};

    m.product_id      = stmt.column_int(0);
    m.name            = stmt.column_text(1);
    double price      = stmt.column_double(2);
    int quantity      = stmt.column_int(3);
    double discount   = stmt.column_double(4);

    // From SQL (demonstrates use of ABS and ROUND)
    double abs_price_sql      = stmt.column_double(5);
    double rounded_price_sql  = stmt.column_double(6);

    // Use the SQL-computed values where possible
    m.abs_price      = abs_price_sql;
    m.rounded_price  = rounded_price_sql;

    // Remaining calculations are done in C++ using <cmath>
    m.ceil_price     = std::ceil(price);
    m.floor_price    = std::floor(price);

    // Exponential of discount_rate/100
    m.exp_discount   = std::exp(discount / 100.0);

    // Natural log of price (guard against non-positive values)
    if (price > 0.0) {
      m.ln_price = std::log(price);
    } else {
      m.ln_price = std::numeric_limits<double>::quiet_NaN();
    }

    // log2(quantity) (guard against non-positive values)
    if (quantity > 0) {
      m.log2_quantity = std::log2(static_cast<double>(quantity));
    } else {
      m.log2_quantity = std::numeric_limits<double>::quiet_NaN();
    }

    // Trigonometric functions of discount_rate (in radians)
    m.sin_discount   = std::sin(discount);
    m.cos_discount   = std::cos(discount);
    m.tan_discount   = std::tan(discount);

    // sqrt(quantity) (guard against negative)
    if (quantity >= 0) {
      m.sqrt_quantity = std::sqrt(static_cast<double>(quantity));
    } else {
      m.sqrt_quantity = std::numeric_limits<double>::quiet_NaN();
    }

    results.push_back(std::move(m));
  }

  return results;
}

}  // namespace mathematical_operations_analysis
```

