#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace replace_text_in_notes {

struct Note {
  sqlgen::PrimaryKey<int> note_id;
  std::string content;
};

struct UpdatedNote {
  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::connection db{"test_db.sqlite"};

  // Create a context bound to the Notes table
  auto ctx = make_context<Note>(db);

  // 1. Select all notes
  auto notes = ctx.all();

  // Helper lambda to replace all occurrences of "foo" with "bar"
  auto replace_foo_with_bar = [](const std::string &text) -> std::string {
    const std::string from = "foo";
    const std::string to   = "bar";

    if (from.empty()) {
      return text;
    }

    std::string result = text;
    std::size_t pos = 0;
    while ((pos = result.find(from, pos)) != std::string::npos) {
      result.replace(pos, from.size(), to);
      pos += to.size();
    }
    return result;
  };

  // 2. Update notes in the database where a replacement is needed
  for (auto &note : notes) {
    std::string new_content = replace_foo_with_bar(note.content);
    if (new_content != note.content) {
      note.content = new_content;
      ctx.update(note);
    }
  }

  // 3. Re-read the notes to return an updated view for verification
  auto updated_notes_raw = ctx.all();

  std::vector<UpdatedNote> result;
  result.reserve(updated_notes_raw.size());
  for (auto &note : updated_notes_raw) {
    result.push_back(UpdatedNote{
        note.note_id,
        note.content,
    });
  }

  return result;
}

}  // namespace replace_text_in_notes
