/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Open / create SQLite database
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Ensure foreign keys are enforced in SQLite
  conn.execute("PRAGMA foreign_keys = ON;");

  // Create tables with cascade behavior (drop existing ones first to reset state)
  conn.execute("DROP TABLE IF EXISTS Child;");
  conn.execute("DROP TABLE IF EXISTS Parent;");

  // Use sqlgen to create tables with FK ON DELETE CASCADE
  // Parent table
  sqlgen::createTable<Parent>(conn);

  // Child table with explicit ON DELETE CASCADE on the foreign key
  sqlgen::Table<Child> childTable(conn);
  childTable.dropIfExists();  // ensure clean slate if createTable<Child> was called elsewhere

  conn.execute(
      "CREATE TABLE Child ("
      "child_id INTEGER PRIMARY KEY, "
      "parent_id INTEGER, "
      "note TEXT, "
      "FOREIGN KEY(parent_id) REFERENCES Parent(parent_id) ON DELETE CASCADE"
      ");");

  // Insert a parent row
  {
    sqlgen::Table<Parent> parentTable(conn);
    Parent p;
    p.parent_id = 1;
    p.name = "Parent 1";
    parentTable.insert(p);
  }

  // Insert associated child rows
  {
    sqlgen::Table<Child> childTable2(conn);

    Child c1;
    c1.child_id = 1;
    c1.parent_id = 1;
    c1.note = "Child 1 of Parent 1";
    childTable2.insert(c1);

    Child c2;
    c2.child_id = 2;
    c2.parent_id = 1;
    c2.note = "Child 2 of Parent 1";
    childTable2.insert(c2);
  }

  // Delete the parent row
  {
    sqlgen::Table<Parent> parentTable(conn);
    parentTable.erase(sqlgen::where("parent_id = ?", 1));
