  // Verify children with parent_id = 1 are deleted (cascade)
  {
    sqlgen::Table<Child> childTable3(conn);
    auto remainingChildren = childTable3.select(sqlgen::where("parent_id = ?", 1));
    // If cascade worked, there should be zero rows
    return remainingChildren.empty();
  }
