#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace column_is_null_checks {

struct Profile {
  sqlgen::PrimaryKey<int> profile_id;
  std::string display_name;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

struct Result {
  int profile_id;
  std::string display_name;
};

std::vector<Result> column_is_null_checks() {
  // Connect to the SQLite database "test_db.sqlite"
  sqlgen::sqlite::database db("test_db.sqlite");

  // Register the Profile entity mapping with sqlgen
  sqlgen::Entity<Profile> profile_entity("Profile");
  profile_entity
      .field(&Profile::profile_id, "profile_id")
      .field(&Profile::display_name, "display_name")
      .field(&Profile::bio, "bio")
      .field(&Profile::avatar_url, "avatar_url");

  sqlgen::Registry registry;
  registry.register_entity(profile_entity);

  sqlgen::sqlite::connection conn(db, registry);

  // Filter rows where at least one of the optional fields is NULL
  sqlgen::Query<Profile> query(conn);

  // WHERE bio IS NULL OR avatar_url IS NULL
  query.where(
      sqlgen::is_null(&Profile::bio) ||
      sqlgen::is_null(&Profile::avatar_url));

  std::vector<Result> results;
  for (auto&& row : query.execute()) {
    Result r;
    r.profile_id = row.profile_id.value();  // PrimaryKey<T> -> T
    r.display_name = row.display_name;
    results.push_back(std::move(r));
  }

  return results;
}

}  // namespace column_is_null_checks
