#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  try {
    // 1. Open SQLite connection to "test_db.sqlite"
    sqlgen::sqlite::connection conn{"test_db.sqlite"};

    // 2. Create a write session
    auto session = sqlgen::make_session(conn);

    // 3. Create Account table (drop if exists to have deterministic content)
    session.execute(R"SQL(
      DROP TABLE IF EXISTS Account;
    )SQL");

    session.execute(R"SQL(
      CREATE TABLE IF NOT EXISTS Account(
        account_id INTEGER PRIMARY KEY,
        balance    REAL NOT NULL,
        status     TEXT NOT NULL
      );
    )SQL");

    // 4. Insert initial data
    {
      auto writer = session.writer<Account>();

      writer.insert(Account{1, 100.0, "active"});
      writer.insert(Account{2, 200.0, "inactive"});
      writer.insert(Account{3, 300.0, "active"});
    }

    // 5. Perform update operations using set(...)

    // Example 1: Give a 50.0 bonus to all active accounts
    {
      auto writer = session.writer<Account>();
      using A = Account;

      writer.update()
          .where(sqlgen::field<&A::status>() == std::string("active"))
          .set(
            sqlgen::field<&A::balance>() =
              sqlgen::field<&A::balance>() + 50.0
          )
          .execute();
    }

    // Example 2: Deactivate accounts whose balance is < 200 after the bonus
    {
      auto writer = session.writer<Account>();
      using A = Account;

      writer.update()
          .where(sqlgen::field<&A::balance>() < 200.0)
          .set(sqlgen::field<&A::status>() = std::string("inactive"))
          .execute();
    }

    // 6. Verify that changes persisted by reading back the rows
    {
      auto reader = session.reader<Account>();
      using A = Account;

      auto accounts = reader.select().execute();

      // We expect:
      // id 1: 100 + 50 = 150, status "inactive" (changed in step 2)
      // id 2: 200, status "inactive" (unchanged in step 2)
      // id 3: 300 + 50 = 350, status "active" (unchanged in step 2)
      if (accounts.size() != 3) {
        return false;
      }

      const Account* acc1 = nullptr;
      const Account* acc2 = nullptr;
      const Account* acc3 = nullptr;

      for (const auto& acc : accounts) {
        if (acc.account_id == 1) acc1 = &acc;
        else if (acc.account_id == 2) acc2 = &acc;
        else if (acc.account_id == 3) acc3 = &acc;
      }

      if (!acc1 || !acc2 || !acc3) {
        return false;
      }

      // Simple value checks (allowing for direct equality since we used exact doubles)
      if (acc1->balance != 150.0 || acc1->status != "inactive") return false;
      if (acc2->balance != 200.0 || acc2->status != "inactive") return false;
      if (acc3->balance != 350.0 || acc3->status != "active")   return false;
    }

    return true;
  } catch (...) {
    // If anything fails (connection, SQL, or logic), return false.
    return false;
  }
}

}  // namespace update_set_operations
```

