```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier
 * and the name of a product, if any. Demonstrates a FULL JOIN using sqlgen by
 * emulating it as LEFT JOIN (suppliers -> products) UNION ALL RIGHT JOIN
 * (products -> suppliers as left).
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;

  // Open connection to SQLite database
  sqlite::connection db{"test_db.sqlite"};

  // Describe tables to sqlgen
  auto suppliers = table<Supplier>("Supplier");
  auto products  = table<Product>("Product");

  // We emulate FULL OUTER JOIN using UNION of LEFT JOINs:
  //
  // 1) Suppliers LEFT JOIN Products
  // 2) Products LEFT JOIN Suppliers (to collect products having no supplier)
  //
  // For the result, we adapt the "left" table's name field into `supplier_name`,
  // and the "right" table's name field into `product_name` where applicable.

  struct Row1 {
    std::string supplier_name;
    std::optional<std::string> product_name;
  };

  struct Row2 {
    std::string supplier_name;
    std::optional<std::string> product_name;
  };

  // Query 1: suppliers LEFT JOIN products
  auto q1 = select(
               suppliers.name.as(&Row1::supplier_name),
               products.name.as(&Row1::product_name))
               .from(suppliers
                     .left_join(products,
                                suppliers.supplier_id == products.supplier_id));

  // Query 2: products with no matching supplier (i.e., RIGHT JOIN emulation)
  // We LEFT JOIN Supplier from Product and filter rows where Supplier is NULL,
  // then map product name to `product_name` and leave `supplier_name` empty.
  auto q2 = select(
               // Empty supplier name for products that don't have a supplier
               literal(std::string{}).as(&Row2::supplier_name),
               products.name.as(&Row2::product_name))
               .from(products.left_join(
                   suppliers, products.supplier_id == suppliers.supplier_id))
               .where(is_null(suppliers.supplier_id));

  // Execute both queries
  std::vector<Row1> rows1;
  std::vector<Row2> rows2;

  db(q1, rows1);
  db(q2, rows2);

  // Merge into result vector of SupProd
  std::vector<SupProd> result;
  result.reserve(rows1.size() + rows2.size());

  for (auto &r : rows1) {
    result.push_back(SupProd{r.supplier_name, r.product_name});
  }
  for (auto &r : rows2) {
    result.push_back(SupProd{r.supplier_name, r.product_name});
  }

  return result;
}

}  // namespace full_join_suppliers_products
```

