/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts,
                                               const std::vector<Employee>& emps) {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // Create tables if they do not already exist
  {
    auto dept_table = make_table<Department>("Department");
    auto emp_table  = make_table<Employee>("Employee");
    db.execute(dept_table.create_if_not_exists());
    db.execute(emp_table.create_if_not_exists());
  }

  // Clear existing rows to make this analysis self-contained/deterministic
  db.execute("DELETE FROM Employee;");
  db.execute("DELETE FROM Department;");

  // Insert provided departments and employees
  {
    auto dept_table = make_table<Department>("Department");
    auto emp_table  = make_table<Employee>("Employee");

    for (const auto& d : depts) {
      db.execute(
        insert_into(dept_table)
          .set(dept_table(&Department::department_id) = d.department_id,
               dept_table(&Department::department_name) = d.department_name,
               dept_table(&Department::location) = d.location));
    }

    for (const auto& e : emps) {
      db.execute(
        insert_into(emp_table)
          .set(emp_table(&Employee::employee_id) = e.employee_id,
               emp_table(&Employee::department_id) = e.department_id,
               emp_table(&Employee::first_name) = e.first_name,
               emp_table(&Employee::last_name)  = e.last_name,
               emp_table(&Employee::salary)     = e.salary));
    }
  }

  JoinAnalysis analysis;

  // Helper lambda to run a query and materialize JoinResult rows
  auto fetch_join_results =
      [&db](const std::string& sql) -> std::vector<JoinResult> {
        std::vector<JoinResult> results;

        db.query(sql, [&](sqlite::Row& row) {
          JoinResult jr;

          // Column 0: department_name
          if (!row.is_null(0)) {
            jr.department_name = row.get<std::string>(0);
          }

          // Column 1: first_name
          if (!row.is_null(1)) {
            jr.first_name = row.get<std::string>(1);
          }

          // Column 2: last_name
          if (!row.is_null(2)) {
            jr.last_name = row.get<std::string>(2);
          }

          // Column 3: salary
          if (!row.is_null(3)) {
            jr.salary = row.get<double>(3);
          }

          results.emplace_back(std::move(jr));
        });

        return results;
      };

  // 1. INNER JOIN: employees with assigned departments
  {
    const std::string sql =
        "SELECT d.department_name, e.first_name, e.last_name, e.salary "
        "FROM Department d "
        "INNER JOIN Employee e ON d.department_id = e.department_id;";
    analysis.inner_join_results = fetch_join_results(sql);
  }

  // 2. LEFT JOIN: all employees, even without departments
  {
    const std::string sql =
        "SELECT d.department_name, e.first_name, e.last_name, e.salary "
        "FROM Employee e "
        "LEFT JOIN Department d ON e.department_id = d.department_id;";
    analysis.left_join_results = fetch_join_results(sql);
  }

  // 3. RIGHT JOIN: all departments, even without employees
  // SQLite does not support RIGHT JOIN natively; simulate it by
  // switching tables in a LEFT JOIN (departments as the left table).
  {
    const std::string sql =
        "SELECT d.department_name, e.first_name, e.last_name, e.salary "
        "FROM Department d "
        "LEFT JOIN Employee e ON e.department_id = d.department_id;";
    analysis.right_join_results = fetch_join_results(sql);
  }

  // 4. FULL JOIN: all employees and departments
  // SQLite has no FULL OUTER JOIN; approximate via UNION of
  // left and right join perspectives.
  {
    const std::string sql =
        "SELECT d.department_name, e.first_name, e.last_name, e.salary "
        "FROM Department d "
        "LEFT JOIN Employee e ON e.department_id = d.department_id "
        "UNION "
        "SELECT d.department_name, e.first_name, e.last_name, e.salary "
        "FROM Employee e "
        "LEFT JOIN Department d ON e.department_id = d.department_id;";
    analysis.full_join_results = fetch_join_results(sql);
  }

  return analysis;
}

}  // namespace analyze_department_employees
