```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;         // 0–6 (SQLite: 0=Sunday, 1=Monday, …, 6=Saturday)
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity
 *              sold for each weekday (SQLite: 0=Sunday, ..., 6=Saturday).
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;

  // Open the SQLite database "test_db.sqlite"
  sqlite::connection db{"test_db.sqlite"};

  // Build the expression to extract weekday from sale_time:
  // SQLite: strftime('%w', datetime) → '0'..'6' as text.
  // Cast it to INTEGER so we can treat it as int.
  auto weekday_expr = cast<int>(strftime<std::string>("%w", &Sales::sale_time));

  // Build and execute the query:
  // SELECT CAST(strftime('%w', sale_time) AS INTEGER) AS weekday,
  //        SUM(quantity) AS total_quantity
  // FROM Sales
  // GROUP BY weekday
  auto rows = db.select(
      weekday_expr.as("weekday"),
      sum(&Sales::quantity).as("total_quantity")
    )
    .from<Sales>()
    .group_by(weekday_expr)
    .execute();

  std::vector<WeekdayStats> result;
  result.reserve(rows.size());

  for (const auto &row : rows) {
    WeekdayStats stats{};
    stats.weekday = row.template get<int>("weekday");
    stats.total_quantity = row.template get<int>("total_quantity");
    result.push_back(stats);
  }

  return result;
}

}  // namespace weekday_sales_analysis
