namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;

  // Open SQLite connection to the given database
  sqlite::connection conn{"test_db.sqlite"};

  // Define ORM mapping
  orm<Project> project_orm{"Project", &Project::project_id, &Project::name};
  orm<TimeLog> timelog_orm{
      "TimeLog",
      &TimeLog::log_id,
      &TimeLog::project_id,
      &TimeLog::start_time,
      &TimeLog::end_time};

  orm<TimeMetrics> metrics_orm{
      // No table name because this will be used as a row-mapping target
      "", &TimeMetrics::project_id, &TimeMetrics::name, &TimeMetrics::day,
      &TimeMetrics::month, &TimeMetrics::year, &TimeMetrics::hour,
      &TimeMetrics::minute, &TimeMetrics::second, &TimeMetrics::duration_days};

  // Build a query that:
  // 1. Joins Project and TimeLog
  // 2. Extracts date/time components from start_time
  // 3. Computes days_between(start_time, end_time)
  // 4. Groups by project and week (using SQLite's strftime('%Y-%W', ...))
  //
  // Note: SQLite does not have DAY(), MONTH(), YEAR(), HOUR(), MINUTE(), SECOND()
  // or DAYS_BETWEEN() built-ins, so we emulate them with strftime() and
  // julianday(). This matches the intent of the reference SQL.
  //
  // Weekly grouping is done using strftime('%Y-%W', t.start_time) AS week_key
  // and grouping by that key along with the project.
  std::string sql = R"SQL(
    SELECT
      p.project_id                          AS project_id,
      p.name                                AS name,
      CAST(strftime('%d', t.start_time) AS INTEGER) AS day,
      CAST(strftime('%m', t.start_time) AS INTEGER) AS month,
      CAST(strftime('%Y', t.start_time) AS INTEGER) AS year,
      CAST(strftime('%H', t.start_time) AS INTEGER) AS hour,
      CAST(strftime('%M', t.start_time) AS INTEGER) AS minute,
      CAST(strftime('%S', t.start_time) AS INTEGER) AS second,
      -- Average duration in days within the project-week
      AVG(julianday(t.end_time) - julianday(t.start_time)) AS duration_days
    FROM Project p
    INNER JOIN TimeLog t ON p.project_id = t.project_id
    GROUP BY
      p.project_id,
      p.name,
      strftime('%Y-%W', t.start_time)
  )SQL";

  // Execute raw SQL and map rows into TimeMetrics via sqlgen
  auto stmt = conn.prepare(sql);
  std::vector<TimeMetrics> results;
  stmt.execute(metrics_orm, std::back_inserter(results));

  return results;
}

}  // namespace project_time_tracking

