#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Build the SELECT query that chooses rows from Source where value > 100,
  // and selects only the "value" column to match the Target table schema.
  auto select_query = select(columns<&Source::value>())
                        .from<Source>()
                        .where(&Source::value > 100);

  // Build the CREATE TABLE AS SELECT query for Target using the SELECT above.
  auto query = create_table_as_select_<Target>(select_query);

  // Return the generated SQL string.
  return query.value();
}

